#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
    return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=1e3+5;
int a[MAXN][MAXN],n;
signed main(void)
{
    // freopen("in.txt","r",stdin);
    // freopen("out.txt","w",stdout);
    n=read();
    FOR(i,1,n)
    {
    	FOR(j,1,n)
    	{
    		a[i][j]=read();
		}
	}
	FOR(i,1,n)
	{
		FOR(j,1,n)
		{
			int ans=1;
			FOR(k,1,n)
			{
				FOR(l,1,n)
				{
					if(a[i][j]<a[l][k])
					{
						++ans;
					}
				}
			}
			write(ans);
			pc(' ');
		}
		puts("");
	}
    return false;
}
